from flask import Flask, render_template, request
import traceback

app = Flask(__name__)

def calculate_check_digit(id_number):
    weights = [2, 7, 6, 5, 4, 3, 2, 1]
    check_digit = 0
    for i in range(len(id_number)):
        check_digit += int(id_number[i]) * weights[i]

    check_digit = (12 - (check_digit % 11)) % 10

    return str(check_digit)

def validate_id_number(id_number):
    weights = [7, 6, 5, 4, 3, 2, 1, 0, 9, 8, 7, 6, 5, 4, 3, 2, 1]
    sum = 0
    for i in range(len(id_number)-1):
        sum += int(id_number[i]) * weights[i]

    check_digit = (12 - (sum % 11)) % 10

    return check_digit == int(id_number[-1])

@app.route('/', methods=['GET', 'POST'])
def index():
    if request.method == 'POST':
        try:
            id_number = request.form['id_number']
            if len(id_number) == 15:
                id_number = id_number[:6] + '19' + id_number[6:] + calculate_check_digit(id_number)
            if len(id_number) == 18:
                is_valid = validate_id_number(id_number)
                if is_valid:
                    gender = "男" if int(id_number[-2]) % 2 == 1 else "女"
                    birth_date = id_number[6:14]
                    birth_place = id_number[:6]
                    return render_template('result.html', is_valid=is_valid, gender=gender, birth_date=birth_date, birth_place=birth_place)
            return render_template('result.html', is_valid=False)
        except Exception as e:
            traceback.print_exc()
            return "Internal Server Error"
    return render_template('index.html')

if __name__ == '__main__':
    app.run()
